function configuracionDte(PDO $pdo): array {
 $q=$pdo->query('SELECT * FROM dte_configuracion WHERE activo=1 ORDER BY id DESC LIMIT 1');$c=$q->fetch();if(!$c)throw new RuntimeException('Configure los datos del emisor DTE antes de emitir.');
 $amb=entornoAtenea('DTE_ENV',(string)$c['ambiente']);if(!in_array($amb,['simulation','test','production'],true))throw new RuntimeException('Ambiente DTE no válido.');$suf=$amb==='production'?'PRODUCTION':'TEST';
 return $c+['ambiente'=>$amb,'usuario_hacienda'=>entornoAtenea('DTE_HACIENDA_USER'),'password_hacienda'=>entornoAtenea('DTE_HACIENDA_PASSWORD'),'certificado'=>entornoAtenea('DTE_CERTIFICATE_PATH'),'certificado_secreto'=>entornoAtenea('DTE_CERTIFICATE_SECRET'),'sign_url'=>entornoAtenea('DTE_SIGN_URL'),'auth_url'=>entornoAtenea('DTE_AUTH_URL_'.$suf),'receive_url'=>entornoAtenea('DTE_RECEIVE_URL_'.$suf),'query_url'=>entornoAtenea('DTE_QUERY_URL_'.$suf),'invalidate_url'=>entornoAtenea('DTE_INVALIDATE_URL_'.$suf)];
}
function proveedorDte(array $c):DteProviderInterface{return $c['ambiente']==='simulation'?new SimulationDteProvider():new HaciendaDteProvider();}
function uuidDte():string{$b=random_bytes(16);$b[6]=chr((ord($b[6])&15)|64);$b[8]=chr((ord($b[8])&63)|128);return strtoupper(vsprintf('%s%s-%s-%s-%s-%s%s%s',[...str_split(bin2hex($b),4)]));}
function siguienteNumeroControl(PDO $pdo,array $c):string{$e=strtoupper($c['codigo_establecimiento']);$p=strtoupper($c['punto_venta']);$pdo->prepare('INSERT INTO dte_correlativos(tipo_dte,establecimiento,punto_venta,ultimo) VALUES(\'01\',:e,:p,1) ON DUPLICATE KEY UPDATE ultimo=LAST_INSERT_ID(ultimo+1)')->execute(['e'=>$e,'p'=>$p]);$n=(int)$pdo->lastInsertId();if($n<1)$n=1;return 'DTE-01-'.$e.$p.'-'.str_pad((string)$n,15,'0',STR_PAD_LEFT);}
function decimalJson(string $v):float{return (float)number_format((float)$v,2,'.','');}
