 $snap=is_array($p['direccion_snapshot'])?$p['direccion_snapshot']:json_decode((string)$p['direccion_snapshot'],true,512,JSON_THROW_ON_ERROR);$fecha=new DateTimeImmutable($p['paid_at']?:'now');$items=[];
 foreach($p['detalles']as$i)$items[]=['numItem'=>count($items)+1,'tipoItem'=>1,'numeroDocumento'=>null,'cantidad'=>(int)$i['cantidad'],'codigo'=>$i['sku']?:('PROD-'.$i['producto_id']),'codTributo'=>null,'uniMedida'=>59,'descripcion'=>$i['nombre_producto'],'precioUni'=>decimalJson($i['precio_normal']),'montoDescu'=>decimalJson(centavosDinero(dineroCentavos($i['descuento_unitario'])*(int)$i['cantidad'])),'ventaNoSuj'=>0.0,'ventaExenta'=>0.0,'ventaGravada'=>decimalJson($i['subtotal']),'tributos'=>null,'psv'=>0.0,'noGravado'=>0.0,'ivaItem'=>0.0];
 $usuario=$p['usuario'];$total=decimalJson($p['total']);$direccion=['departamento'=>str_pad((string)$c['departamento_codigo'],2,'0',STR_PAD_LEFT),'municipio'=>str_pad((string)$c['municipio_codigo'],2,'0',STR_PAD_LEFT),'complemento'=>mb_substr($c['direccion'],0,200)];
 return ['identificacion'=>['version'=>1,'ambiente'=>$c['ambiente']==='production'?'01':'00','tipoDte'=>'01','numeroControl'=>$p['numero_control'],'codigoGeneracion'=>$p['codigo_generacion'],'tipoModelo'=>1,'tipoOperacion'=>1,'tipoContingencia'=>null,'motivoContin'=>null,'fecEmi'=>$fecha->format('Y-m-d'),'horEmi'=>$fecha->format('H:i:s'),'tipoMoneda'=>'USD'],'documentoRelacionado'=>null,'emisor'=>['nit'=>$c['nit'],'nrc'=>$c['nrc'],'nombre'=>$c['razon_social'],'codActividad'=>$c['actividad_codigo'],'descActividad'=>$c['actividad_descripcion'],'nombreComercial'=>$c['nombre_comercial']?:null,'tipoEstablecimiento'=>'02','direccion'=>$direccion,'telefono'=>$c['telefono'],'correo'=>$c['correo'],'codEstableMH'=>null,'codEstable'=>$c['codigo_establecimiento'],'codPuntoVentaMH'=>null,'codPuntoVenta'=>$c['punto_venta']],'receptor'=>['tipoDocumento'=>null,'numDocumento'=>null,'nrc'=>null,'nombre'=>trim($usuario['nombre'].' '.$usuario['apellido']),'codActividad'=>null,'descActividad'=>null,'direccion'=>['departamento'=>str_pad((string)($snap['departamento_id']??1),2,'0',STR_PAD_LEFT),'municipio'=>str_pad((string)($snap['municipio_id']??1),2,'0',STR_PAD_LEFT),'complemento'=>mb_substr(($snap['direccion_detallada']??'').' '.($snap['municipio']??'').' '.($snap['departamento']??''),0,200)],'telefono'=>$snap['telefono']??null,'correo'=>$usuario['correo']],'otrosDocumentos'=>null,'ventaTercero'=>null,'cuerpoDocumento'=>$items,'resumen'=>['totalNoSuj'=>0.0,'totalExenta'=>0.0,'totalGravada'=>decimalJson(centavosDinero(dineroCentavos($p['subtotal'])-dineroCentavos($p['descuento']))),'subTotalVentas'=>decimalJson($p['subtotal']),'descuNoSuj'=>0.0,'descuExenta'=>0.0,'descuGravada'=>decimalJson($p['descuento']),'porcentajeDescuento'=>0.0,'totalDescu'=>decimalJson($p['descuento']),'tributos'=>null,'subTotal'=>decimalJson(centavosDinero(dineroCentavos($p['total'])-dineroCentavos($p['impuestos']))),'ivaRete1'=>0.0,'reteRenta'=>0.0,'montoTotalOperacion'=>$total,'totalNoGravado'=>decimalJson($p['envio']),'totalPagar'=>$total,'totalLetras'=>strtoupper(numeroEnLetrasSimple(dineroCentavos($p['total']))),'totalIva'=>decimalJson($p['impuestos']),'saldoFavor'=>0.0,'condicionOperacion'=>1,'pagos'=>[['codigo'=>'03','montoPago'=>$total,'referencia'=>$p['stripe_payment_intent_id'],'plazo'=>null,'periodo'=>null]],'numPagoElectronico'=>$p['stripe_payment_intent_id']],'extension'=>['nombEntrega'=>$snap['receptor']??null,'docuEntrega'=>null,'nombRecibe'=>$snap['receptor']??null,'docuRecibe'=>null,'placaVehiculo'=>null,'observaciones'=>'Entrega: '.($snap['direccion_detallada']??'')],'apendice'=>$c['ambiente']==='simulation'?[['campo'=>'advertencia','etiqueta'=>'Validez fiscal','valor'=>'SIMULACION SIN VALIDEZ FISCAL']]:null];
}
function numeroEnLetrasSimple(int $c):string{return intdiv($c,100).' DÓLARES CON '.str_pad((string)($c%100),2,'0',STR_PAD_LEFT).' CENTAVOS';}
function validarJsonDte(array $d):void{require_once ATENEA_ROOT.'/vendor/autoload.php';$schema=json_decode(file_get_contents(ATENEA_ROOT.'/resources/dte/schemas/fe-fc-v1.json'),false,512,JSON_THROW_ON_ERROR);$v=new Opis\JsonSchema\Validator();$r=$v->validate(json_decode(json_encode($d,JSON_THROW_ON_ERROR)), $schema);if(!$r->isValid())throw new RuntimeException('El DTE no cumple el JSON Schema de Factura v1.');}
function tokenHacienda(array $c):string{$manual=entornoAtenea('DTE_ACCESS_TOKEN');if($manual!=='')return $manual;$ch=curl_init($c['auth_url']);curl_setopt_array($ch,[CURLOPT_POST=>true,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>30,CURLOPT_HTTPHEADER=>['Content-Type: application/x-www-form-urlencoded'],CURLOPT_POSTFIELDS=>http_build_query(['user'=>$c['usuario_hacienda'],'pwd'=>$c['password_hacienda']])]);$raw=curl_exec($ch);$code=curl_getinfo($ch,CURLINFO_RESPONSE_CODE);if($raw===false||$code>=400)throw new RuntimeException('No fue posible autenticar con Hacienda.');$r=json_decode($raw,true,512,JSON_THROW_ON_ERROR);$token=(string)($r['body']['token']??$r['token']??'');if(str_starts_with($token,'Bearer '))$token=substr($token,7);if($token==='')throw new RuntimeException('Hacienda no devolvió un token utilizable.');return $token;}
function solicitudHacienda(string $m,string $url,array $body,array $c):array{$token=tokenHacienda($c);$ch=curl_init($url);curl_setopt_array($ch,[CURLOPT_CUSTOMREQUEST=>$m,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>30,CURLOPT_HTTPHEADER=>['Authorization: Bearer '.$token,'Content-Type: application/json'],CURLOPT_POSTFIELDS=>json_encode($body,JSON_THROW_ON_ERROR)]);$raw=curl_exec($ch);$code=curl_getinfo($ch,CURLINFO_RESPONSE_CODE);if($raw===false||$code>=400)throw new RuntimeException('Hacienda rechazó o no respondió la solicitud.');return json_decode($raw,true,512,JSON_THROW_ON_ERROR);}
function renderizarPdfDte(array $d,array $p,array $c,bool $sim):string{require_once ATENEA_ROOT.'/vendor/autoload.php';$qr=(new Endroid\QrCode\Builder\Builder())->writer(new Endroid\QrCode\Writer\SvgWriter())->data(atenea_url_absoluta('src/dte/ver.php?codigo='.$d['identificacion']['codigoGeneracion']))->size(150)->margin(4)->build()->getDataUri();$logo=ATENEA_ROOT.'/img/atenea-logo.png';$logoUri=is_file($logo)?'data:image/png;base64,'.base64_encode(file_get_contents($logo)):'';ob_start();?>
<!doctype html><html><head><meta charset="utf-8"><style>@page{margin:20px 26px}body{font:10px DejaVu Sans;color:#26342c}.head{border-bottom:4px solid #4b7f52;padding-bottom:8px}.logo{width:105px}.warning{background:#fff3cd;border:2px solid #b7791f;padding:7px;text-align:center;font-weight:bold}.grid{width:100%;border-collapse:collapse;margin-top:8px}.grid th{background:#4b7f52;color:white}.grid th,.grid td{border:1px solid #b7c7b9;padding:5px;vertical-align:top}.meta{width:100%;margin-top:6px}.meta td{width:50%;padding:3px}.totals{margin-left:auto;width:45%}thead{display:table-header-group}.page:after{content:counter(page)}</style></head><body><?php if($sim):?><div class="warning">DOCUMENTO DE SIMULACIÓN — SIN VALIDEZ FISCAL — NO ENVIADO A HACIENDA</div><?php endif;?><table class="head" width="100%"><tr><td><?php if($logoUri):?><img class="logo" src="<?=$logoUri?>"><?php endif;?><br><b><?=atenea_e($c['nombre_comercial'])?></b><br><?=atenea_e($c['razon_social'])?><br><?=atenea_e($c['direccion'])?></td><td align="right"><h2>Documento Tributario Electrónico - Factura</h2><img src="<?=$qr?>" width="105"><br>QR de consulta</td></tr></table><table class="meta"><tr><td><b>Código de generación:</b><br><?=atenea_e($d['identificacion']['codigoGeneracion'])?></td><td><b>Número de control:</b><br><?=atenea_e($d['identificacion']['numeroControl'])?></td></tr><tr><td><b>Sello:</b><br><?=atenea_e((string)($d['_sello']??'Pendiente de recepción'))?></td><td><b>Modelo / Versión / Transmisión:</b><br>Previo / 1 / Normal</td></tr><tr><td><b>Fecha y hora:</b> <?=atenea_e($d['identificacion']['fecEmi'].' '.$d['identificacion']['horEmi'])?></td><td><b>Forma de pago:</b> <?=atenea_e(metodoPagoPedido($p))?></td></tr></table><h3>Datos del receptor</h3><p><b><?=atenea_e($d['receptor']['nombre'])?></b> · <?=atenea_e((string)$d['receptor']['correo'])?><br><?=atenea_e($d['receptor']['direccion']['complemento'])?></p><table class="grid"><thead><tr><th>Cant.</th><th>Unidad</th><th>Código</th><th>Descripción</th><th>Precio</th><th>Descuento</th><th>Gravado</th></tr></thead><tbody><?php foreach($d['cuerpoDocumento']as$i):?><tr><td><?=$i['cantidad']?></td><td>Unidad</td><td><?=atenea_e($i['codigo'])?></td><td><?=atenea_e($i['descripcion'])?></td><td>$<?=number_format($i['precioUni'],2)?></td><td>$<?=number_format($i['montoDescu'],2)?></td><td>$<?=number_format($i['ventaGravada'],2)?></td></tr><?php endforeach;?></tbody></table><table class="grid totals"><tr><td>No sujetas</td><td>$<?=number_format($d['resumen']['totalNoSuj'],2)?></td></tr><tr><td>Exentas</td><td>$<?=number_format($d['resumen']['totalExenta'],2)?></td></tr><tr><td>Gravadas</td><td>$<?=number_format($d['resumen']['totalGravada'],2)?></td></tr><tr><td>Descuentos</td><td>$<?=number_format($d['resumen']['totalDescu'],2)?></td></tr><tr><th>Total</th><th>$<?=number_format($d['resumen']['totalPagar'],2)?></th></tr></table><p><b>Valor en letras:</b> <?=atenea_e($d['resumen']['totalLetras'])?></p><p><b>Información de entrega:</b> <?=atenea_e((string)($d['extension']['observaciones']??''))?></p><p><b>Observaciones:</b> <?=atenea_e($sim?'Comprobante generado exclusivamente para pruebas internas.':'Documento sujeto a recepción de Hacienda.')?></p><div align="right">Página <span class="page"></span></div></body></html><?php $html=(string)ob_get_clean();$dom=new Dompdf\Dompdf(['isRemoteEnabled'=>false]);$dom->loadHtml($html,'UTF-8');$dom->setPaper('letter','portrait');$dom->render();return $dom->output();}
function pedidoCompletoDte(PDO $pdo,int $id):?array{$q=$pdo->prepare('SELECT p.*,u.nombre,u.apellido,u.correo FROM pedidos p JOIN usuarios u ON u.id=p.usuario_id WHERE p.id=:id');$q->execute(['id'=>$id]);$p=$q->fetch();if(!$p)return null;$q=$pdo->prepare('SELECT * FROM pedido_detalles WHERE pedido_id=:id ORDER BY id');$q->execute(['id'=>$id]);$p['detalles']=$q->fetchAll();$p['usuario']=['nombre'=>$p['nombre'],'apellido'=>$p['apellido'],'correo'=>$p['correo']];return $p;}
function generarDtePedido(int $pedidoId):array{$pdo=obtenerConexion();$q=$pdo->prepare('SELECT * FROM dte_documentos WHERE pedido_id=:id');$q->execute(['id'=>$pedidoId]);if($d=$q->fetch())return $d;$pdo->beginTransaction();try{$p=pedidoCompletoDte($pdo,$pedidoId);if(!$p||$p['estado']!=='pagado'||$p['payment_status']!=='paid')throw new RuntimeException('Solo se emite DTE después de confirmar el pago.');$c=configuracionDte($pdo);$p['codigo_generacion']=uuidDte();$p['numero_control']=siguienteNumeroControl($pdo,$c);$provider=proveedorDte($c);$doc=$provider->generate($p,$c);validarJsonDte($doc);$doc=$provider->sign($doc,$c);$respuesta=$provider->submit($doc,$c);$json=json_encode(array_diff_key($doc,['_sello'=>true,'_documento_firmado'=>true]),JSON_UNESCAPED_UNICODE|JSON_PRESERVE_ZERO_FRACTION|JSON_THROW_ON_ERROR);$pdf=$provider->getGraphicalRepresentation($doc,$p,$c);$base=getenv('DTE_STORAGE_PATH')?:dirname(ATENEA_ROOT).'/atenea-private/dte';$dir=rtrim($base,'/\\').DIRECTORY_SEPARATOR.date('Y').DIRECTORY_SEPARATOR.date('m');if(!is_dir($dir)&&!mkdir($dir,0700,true)&&!is_dir($dir))throw new RuntimeException('No se creó el almacenamiento privado DTE.');$nombre=$p['codigo_generacion'];$pdfPath=$dir.DIRECTORY_SEPARATOR.$nombre.'.pdf';if(file_put_contents($pdfPath,$pdf,LOCK_EX)===false)throw new RuntimeException('No se guardó el PDF.');$rel=date('Y').'/'.date('m').'/'.$nombre.'.pdf';$q=$pdo->prepare('INSERT INTO dte_documentos(pedido_id,ambiente,codigo_generacion,numero_control,sello_recepcion,estado,schema_version,json_documento,json_sha256,pdf_relpath,pdf_sha256,observaciones,emitido_at) VALUES(:p,:a,:g,:n,:s,:e,:v,:j,:jh,:path,:ph,:o,NOW())');$q->execute(['p'=>$pedidoId,'a'=>$c['ambiente'],'g'=>$nombre,'n'=>$p['numero_control'],'s'=>$respuesta['sello']??null,'e'=>$respuesta['estado'],'v'=>$c['schema_version'],'j'=>$json,'jh'=>hash('sha256',$json),'path'=>$rel,'ph'=>hash('sha256',$pdf),'o'=>$respuesta['observaciones']??null]);$id=(int)$pdo->lastInsertId();$pdo->prepare('INSERT INTO dte_eventos(dte_id,pedido_id,operacion,ambiente,resultado,response_sanitizado,codigo,observaciones) VALUES(:d,:p,\'generate\',:a,:r,:resp,:c,:o)')->execute(['d'=>$id,'p'=>$pedidoId,'a'=>$c['ambiente'],'r'=>'success','resp'=>json_encode(['estado'=>$respuesta['estado']],JSON_THROW_ON_ERROR),'c'=>$respuesta['estado'],'o'=>$respuesta['observaciones']??null]);$pdo->commit();$q=$pdo->prepare('SELECT * FROM dte_documentos WHERE id=:id');$q->execute(['id'=>$id]);return $q->fetch();}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();try{$pdo->prepare("INSERT INTO dte_eventos(pedido_id,operacion,ambiente,resultado,observaciones) VALUES(:p,'generate',:a,'failure',:o)")->execute(['p'=>$pedidoId,'a'=>isset($c['ambiente'])?$c['ambiente']:'unknown','o'=>mb_substr(preg_replace('/[\\r\\n\\t]+/',' ',$e->getMessage()),0,1000)]);}catch(Throwable){}error_log('DTE pedido '.$pedidoId.': '.$e->getMessage());throw $e;}}
